                particles.push({
                    x: x,
                    y: y,
                    size: Math.random() * 3 + 1,
                    speedX: (Math.random() - 0.5) * 50,
                    speedY: (Math.random() - 0.5) * 50,
                    color: color,
                    alpha: 1,
                    lifetime: Math.random() * 500 + 300
