            // Keep player within bounds
            player.x = Math.max(player.width / 2, Math.min(canvas.width - player.width / 2, player.x));

            // Player shooting
            if ((keys[' '] || (touchActive && !playerMoved)) && (performance.now() - lastShotTime > shootCooldown)) {
                shootBullet();
                lastShotTime = performance.now();
            }

            // Update player invincibility
            if (player.invincible) {
                player.invincibleTimer += deltaTime;
                if (player.invincibleTimer >= player.invincibleDuration) {
                    player.invincible = false;
                    player.invincibleTimer = 0;
                }
            }

            // Update bullets
            for (let i = bullets.length - 1; i >= 0; i--) {
                const bullet = bullets[i];
                bullet.y -= bulletSpeed * deltaTime / 1000;
                if (bullet.y < 0) {
                    bullets.splice(i, 1);
                }
            }

            // Spawn enemies
            if (performance.now() - lastEnemySpawnTime > enemySpawnInterval) {
                enemies.push({
                    x: Math.random() * (canvas.width - enemyWidth) + enemyWidth / 2,
                    y: -enemyHeight / 2,
                    width: enemyWidth,
                    height: enemyHeight,
                    color: enemyColor
                });
                lastEnemySpawnTime = performance.now();
                // Gradually decrease spawn interval to increase difficulty
                enemySpawnInterval = Math.max(500, enemySpawnInterval * 0.98);
            }

            // Update enemies
            for (let i = enemies.length - 1; i >= 0; i--) {
                const enemy = enemies[i];
                enemy.y += enemySpeed * deltaTime / 1000;

                // Collision with player
                if (!player.invincible &&
                    enemy.x - enemy.width / 2 < player.x + player.width / 2 &&
                    enemy.x + enemy.width / 2 > player.x - player.width / 2 &&
                    enemy.y - enemy.height / 2 < player.y + player.height / 2 &&
                    enemy.y + enemy.height / 2 > player.y - player.height / 2) {

                    player.lives--;
                    createParticle(player.x, player.y, player.color);
                    enemies.splice(i, 1); // Remove enemy on collision
                    player.invincible = true;
                    player.invincibleTimer = 0;

                    if (player.lives <= 0) {
                        gameOver();
                        return;
                    }
                }

                if (enemy.y > canvas.height + enemyHeight / 2) {
                    enemies.splice(i, 1);
                    // Optionally, penalize player for letting enemies escape
                }
            }

            // Bullet-enemy collision
            for (let i = bullets.length - 1; i >= 0; i--) {
                const bullet = bullets[i];
                for (let j = enemies.length - 1; j >= 0; j--) {
                    const enemy = enemies[j];

                    if (bullet.x - bulletWidth / 2 < enemy.x + enemy.width / 2 &&
                        bullet.x + bulletWidth / 2 > enemy.x - enemy.width / 2 &&
                        bullet.y - bulletHeight / 2 < enemy.y + enemy.height / 2 &&
                        bullet.y + bulletHeight / 2 > enemy.y - enemy.height / 2) {

                        createParticle(enemy.x, enemy.y, enemy.color);
                        bullets.splice(i, 1);
                        enemies.splice(j, 1);
                        score += 10;
                        updateScoreDisplay();
                        break; // Bullet hit an enemy, stop checking this bullet against other enemies
                    }
                }
            }

            // Update particles
            for (let i = particles.length - 1; i >= 0; i--) {
                const p = particles[i];
                p.x += p.speedX * deltaTime / 1000;
                p.y += p.speedY * deltaTime / 1000;
                p.alpha -= (deltaTime / p.lifetime);
                if (p.alpha <= 0) {
                    particles.splice(i, 1);
                }
            }
        }

        function shootBullet() {
            bullets.push({
                x: player.x,
                y: player.y - player.height / 2,
                width: bulletWidth,
                height: bulletHeight,
                color: bulletColor
            });
        }

        function render() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Background (optional, canvas background is set by CSS/body)
            // ctx.fillStyle = '#0d0d1e';
            // ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw player
            ctx.save();
            if (player.invincible && Math.floor(player.invincibleTimer / 100) % 2 === 0) {
                // Blink effect during invincibility
                ctx.globalAlpha = 0.5;
            }
            ctx.fillStyle = player.color;
            ctx.beginPath();
            ctx.moveTo(player.x, player.y - player.height / 2); // Top point
            ctx.lineTo(player.x - player.width / 2, player.y + player.height / 2); // Bottom-left point
            ctx.lineTo(player.x + player.width / 2, player.y + player.height / 2); // Bottom-right point
            ctx.closePath();
            ctx.fill();
            ctx.restore();

            // Draw bullets
            ctx.fillStyle = bulletColor;
            bullets.forEach(bullet => {
                ctx.fillRect(bullet.x - bullet.width / 2, bullet.y - bullet.height / 2, bullet.width, bullet.height);
            });

            // Draw enemies
            ctx.fillStyle = enemyColor;
            enemies.forEach(enemy => {
                ctx.beginPath();
                ctx.moveTo(enemy.x, enemy.y + enemy.height / 2); // Bottom point
                ctx.lineTo(enemy.x - enemy.width / 2, enemy.y - enemy.height / 2); // Top-left point
                ctx.lineTo(enemy.x + enemy.width / 2, enemy.y - enemy.height / 2); // Top-right point
                ctx.closePath();
                ctx.fill();
            });

            // Draw particles
            particles.forEach(p => {
                ctx.save();
                ctx.globalAlpha = p.alpha;
                ctx.fillStyle = p.color;
                ctx.fillRect(p.x - p.size / 2, p.y - p.size / 2, p.size, p.size);
                ctx.restore();
            });

            // Draw lives (simple hearts or icons)
            ctx.fillStyle = '#e53e3e'; // Red for lives
            const lifeSize = 15;
            const lifePadding = 5;
            for (let i = 0; i < player.lives; i++) {
                ctx.beginPath();
                ctx.moveTo(canvas.width - (i + 1) * (lifeSize + lifePadding) - 10, 30);
                ctx.bezierCurveTo(
                    canvas.width - (i + 1) * (lifeSize + lifePadding) - 10 + lifeSize / 2, 20,
                    canvas.width - (i + 1) * (lifeSize + lifePadding) - 10 + lifeSize, 20,
                    canvas.width - (i + 1) * (lifeSize + lifePadding) - 10 + lifeSize / 2, 30
                );
                ctx.bezierCurveTo(
                    canvas.width - (i + 1) * (lifeSize + lifePadding) - 10, 40,
                    canvas.width - (i + 1) * (lifeSize + lifePadding) - 10 - lifeSize / 2, 40,
                    canvas.width - (i + 1) * (lifeSize + lifePadding) - 10, 30
                );
                ctx.fill();
            }
        }

        function gameLoop(currentTime) {
            const deltaTime = currentTime - lastTime;
            lastTime = currentTime;

            if (gameState === 'playing') {
                update(deltaTime);
                render();
            } else if (gameState === 'paused') {
                // Do not update, but still render the last frame with pause screen overlay
                render();
            }

            requestAnimationFrame(gameLoop);
        }

        // Initial setup
        updateHighestScoreDisplay();
        showScreen(menuScreen); // Start with menu screen
        lastTime = performance.now(); // Initialize lastTime for the first frame
        requestAnimationFrame(gameLoop);
    </script>
</body>
